COPY public.code_example (id, page_id, title, language, code, context, sort_order) FROM stdin;
1	5	formulaire/user.rs	rust	// Derive a form from the user model\n#[form(schema = runique_users,\n       fields = [username, email, password])]\npub struct RegisterForm;\n\n#[async_trait]\nimpl RuniqueForm for RegisterForm {\n    impl_form_access!(model);\n\n    async fn clean(&mut self) -> Result<(), StrMap> {\n        let mut errors = StrMap::new();\n        if self.cleaned_string("username").unwrap_or_default().len() < 3 {\n            errors.insert("username".into(), "3 characters minimum".into());\n        }\n        if !self.cleaned_string("email").unwrap_or_default().contains("@") {\n            errors.insert("email".into(), "invalid email address".into());\n        }\n        if self.cleaned_string("password").unwrap_or_default().len() < 10 {\n            errors.insert("password".into(), "10 characters minimum".into());\n        }\n        if errors.is_empty() { Ok(()) } else { Err(errors) }\n    }\n}	formulaire	1
2	5	handler	rust	pub async fn registration_submit(\n    mut request: Request,\n    Prisme(mut form): Prisme<RegisterForm>,\n) -> AppResult<Response> {\n    if request.is_post() && form.is_valid().await {\n        match form.save(&request.engine.db).await {\n            Ok(user) => {\n                auth_login(&request.session, &request.engine.db, user.id).await.ok();\n                return Ok(Redirect::to("/profile").into_response());\n            }\n            Err(err) => form.get_form_mut().database_error(&err),\n        }\n    }\n    context_update!(request => { "registration_form" => &form });\n    request.render("auth/registration.html")\n}	handler	2
3	5	registration.html	html	<form method="post" action="/registration">\n    {# Full render — CSRF included automatically #}\n    {% form.registration_form %}\n    <button type="submit">Sign up</button>\n</form>\n\n{# Field-by-field render — CSRF always included automatically #}\n<form method="post" action="/registration">\n    {% form.registration_form.username %}\n    {% form.registration_form.email %}\n    {% form.registration_form.password %}\n    <button type="submit">Sign up</button>\n</form>	template	3
4	6	formulaire/login.rs	rust	// Manual form — no model, no clean\npub struct LoginForm {\n    pub form: Forms,\n}\n\nimpl RuniqueForm for LoginForm {\n    fn register_fields(form: &mut Forms) {\n        form.field(\n            &TextField::text("username")\n                .label("Username")\n                .required(),\n        );\n        form.field(\n            &TextField::password("password")\n                .label("Password")\n                .required(),\n        );\n    }\n      impl_form_access!();\n}	formulaire	1
5	6	handler	rust	pub async fn login(\n    mut request: Request,\n    Prisme(form): Prisme<LoginForm>,\n) -> AppResult<Response> {\n    if request.is_post() && form.is_valid().await {\n        let username = form.cleaned_string("username").unwrap_or_default();\n        let password = form.cleaned_string("password").unwrap_or_default();\n\n        // Search via the built-in user entity\n        let user_opt = BuiltinUserEntity::find_by_username(&request.engine.db, &username).await;\n\n        match user_opt {\n            Some(user) if verify(&password, user.password_hash()) => {\n                auth_login(&request.session, &request.engine.db, user.user_id()).await?;\n                return Ok(Redirect::to("/profile").into_response());\n            }\n            _ => {}\n        }\n    }\n    request.render("auth/login.html")\n}	handler	2
